import { createClient } from "@/app/lib/supabase/server";
import { notFound } from "next/navigation";

export default async function ShowDetailPage({
  params,
}: {
  params: { id: string };
}) {
  const supabase = await createClient();

  const { data: show, error } = await supabase
    .from("shows")
    .select(`
      id,
      artist,
      program,
      show_date,
      venue,
      city,
      start_time,
      entry_time,
      show_details (*),
      show_admin_notes (*)
    `)
    .eq("id", params.id)
    .single();

  if (error || !show) {
    return notFound();
  }

  return (
    <main className="min-h-screen bg-[#fbf7ef] p-8">
      <div className="mx-auto max-w-3xl space-y-6">
        <h1 className="text-4xl font-black">
          {show.venue || "Neue Show"}
        </h1>

        <div className="rounded-3xl bg-white p-6 shadow-xl space-y-4">
          <Input label="Artist" value={show.artist} />
          <Input label="Programm" value={show.program} />
          <Input label="Datum" value={show.show_date} />
          <Input label="Location" value={show.venue} />
          <Input label="Stadt" value={show.city} />
          <Input label="Einlass" value={show.entry_time} />
          <Input label="Beginn" value={show.start_time} />
        </div>
      </div>
    </main>
  );
}

function Input({
  label,
  value,
}: {
  label: string;
  value: string | null;
}) {
  return (
    <div>
      <p className="text-xs font-black text-zinc-500">{label}</p>
      <p className="text-lg font-semibold">{value || "—"}</p>
    </div>
  );
}